using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- Setup: options with the default reflection-based resolver ---
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) GetTypeInfo<T>() — returns a strongly-typed JsonTypeInfo<T>
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> → Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
Console.WriteLine($"  Serialized: {json}");

Person? roundTripped = JsonSerializer.Deserialize(json, personInfo);
Console.WriteLine($"  Deserialized: {roundTripped}");

// 2) TryGetTypeInfo<T>() — probe without throwing
//    Person is resolvable, so this succeeds:
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? found))
{
    Console.WriteLine($"\nTryGetTypeInfo<Person> → found ({found!.Type.Name})");
}

//    Now use a source-gen context that only knows about Person.
//    Asking for int[] will return false instead of throwing.
var limited = new JsonSerializerOptions { TypeInfoResolver = LimitedContext.Default };

if (limited.TryGetTypeInfo<int[]>(out JsonTypeInfo<int[]>? arrayInfo))
{
    Console.WriteLine($"\nTryGetTypeInfo<int[]> → found ({arrayInfo!.Type.Name})");
}
else
{
    Console.WriteLine($"\nTryGetTypeInfo<int[]> → not available (no exception thrown)");
}

// --- Types ---------------------------------------------------------------
public record Person(string Name, int Age);

[JsonSerializable(typeof(Person))]
internal partial class LimitedContext : JsonSerializerContext;

